// アプリ市場データ整理
const marketData = {
  globalDownloads: 3500,
  japanSmartphoneRate: 92,
  platformShare: {
    googlePlay: 70,
    appStore: 30
  }
};

function calcRevenueShare(totalDownloads, appStoreShare) {
  return totalDownloads * (appStoreShare / 100);
}

const topCategories = ['ゲーム', 'エンタメ', 'フィンテック'];

console.log('世界ダウンロード数:', marketData.globalDownloads, '億件');
console.log('App Storeダウンロード数:', calcRevenueShare(marketData.globalDownloads, marketData.platformShare.appStore), '億件');
console.log('日本トップカテゴリ:', topCategories.join(' / '));
